 ChIP-seq data processing 워크플로우 # 2025.01.02 # Trimming # trimming.sh
#!/bin/bash # Set environment variables export bdir=&#34;/data-blog/bi5/res&#34; export hg38_bowtieidx=&#34;/data-blog/bi5/hg38_bowtie_idx/hg38&#34; export hg38_bwaidx=&#34;/data-blog/bi5/hg38_bwa_index/hg38.fa&#34; export ebv_bowtie2idx=&#34;/data-blog/bi5/EBV_bowtie2_idx/NC_007605.1&#34; export ebv_bwaidx=&#34;/data-blog/bi5/EBV_bwa_index/NC_007605.1.fa&#34; # Set working directory cd /data-blog/bi5/samples # Create output directory mkdir -p trimmed # Set sample list and paths samplist=(&#34;Input&#34; &#34;p65&#34; &#34;RIgG&#34;) trimmomatic_jar=&#34;/data/packages/trimmomatic/Trimmomatic-0.39/trimmomatic-0.39.jar&#34; adapter_path=&#34;/data/packages/trimmomatic/Trimmomatic-0.39/adapters/TruSeq3-PE.fa&#34; # Trimming loop for sampname in &#34;${samplist[@]}&#34;; do mkdir -p &#34;trimmed/${sampname}&#34; java -jar $trimmomatic_jar PE -threads 40 -trimlog &#34;trimmed/${sampname}/log.txt&#34; \ &#34;${sampname}_1.fastq&#34; &#34;${sampname}_2.fastq&#34; \ &#34;trimmed/${sampname}/${sampname}_1.trimmed.fastq&#34; &#34;trimmed/${sampname}/${sampname}_1.unpaired.fastq&#34; \ &#34;trimmed/${sampname}/${sampname}_2.trimmed.fastq&#34; &#34;trimmed/${sampname}/${sampname}_2.unpaired.fastq&#34; \ ILLUMINACLIP:&#34;${adapter_path}&#34;:2:30:10 \ LEADING:3 TRAILING:3 MINLEN:36 done Align # align.sh
#!/bin/bash # Set environment variables export bdir=&#34;/data-blog/bi5/res&#34; export hg38_bowtieidx=&#34;/data-blog/bi5/hg38_bowtie_idx/hg38&#34; export hg38_bwaidx=&#34;/data-blog/bi5/hg38_bwa_index/hg38.fa&#34; export ebv_bowtie2idx=&#34;/data-blog/bi5/EBV_bowtie2_idx/NC_007605.1&#34; export ebv_bwaidx=&#34;/data-blog/bi5/EBV_bwa_index/NC_007605.1.fa&#34; # Set working directory cd /data-blog/bi5/samples # Create directories for alignment results mkdir -p $bdir/aln/bwa mkdir -p $bdir/aln/bwt2 # Set sample list samplist=(&#34;Input&#34; &#34;p65&#34; &#34;RIgG&#34;) # EBV alignment loop for sampname in &#34;${samplist[@]}&#34;; do bwa mem -t 20 -v 2 $ebv_bwaidx \ &#34;trimmed/${sampname}/${sampname}_1.trimmed.fastq&#34; &#34;trimmed/${sampname}/${sampname}_2.trimmed.fastq&#34; \ &gt; &#34;$bdir/aln/bwa/${sampname}_PE.bwa.sam&#34; samtools view -hf 2 &#34;$bdir/aln/bwa/${sampname}_PE.bwa.sam&#34; | \ samtools sort -o &#34;$bdir/aln/bwa/${sampname}_PE.bwa.bam&#34; -O BAM -@ 20 - samtools index -@ 20 &#34;$bdir/aln/bwa/${sampname}_PE.bwa.bam&#34; bamCoverage -b &#34;$bdir/aln/bwa/${sampname}_PE.bwa.bam&#34; \ -o &#34;$bdir/aln/bwa/${sampname}_PE.bwa.bam.bigwig&#34; macs2 callpeak -t &#34;$bdir/aln/bwa/${sampname}_PE.bwa.bam&#34; -f BAMPE \ -n &#34;${sampname}&#34; --outdir &#34;$bdir/peaks_ebv&#34; done # hg38 alignment loop for sampname in &#34;${samplist[@]}&#34;; do bowtie2 -k1 --no-unal -p 40 --qc-filter -x $hg38_bowtieidx \ -1 &#34;trimmed/${sampname}/${sampname}_1.trimmed.fastq&#34; -2 &#34;trimmed/${sampname}/${sampname}_2.trimmed.fastq&#34; \ &gt; &#34;$bdir/aln/bwt2/${sampname}_PE_hg38.sam&#34; samtools view -hf 2 &#34;$bdir/aln/bwt2/${sampname}_PE_hg38.sam&#34; | \ samtools sort -o &#34;$bdir/aln/bwt2/${sampname}_PE_hg38.bam&#34; -O BAM -@ 20 - sambamba view -h -t 20 -f bam -p -F &#34;[XS] == null and not unmapped and not duplicate&#34; \ &#34;$bdir/aln/bwt2/${sampname}_PE_hg38.bam&#34; &gt; &#34;$bdir/aln/bwt2/${sampname}_PE_hg38_u.bam&#34; samtools index -@ 20 &#34;$bdir/aln/bwt2/${sampname}_PE_hg38_u.bam&#34; macs2 callpeak -t &#34;$bdir/aln/bwt2/${sampname}_PE_hg38_u.bam&#34; -f BAMPE \ -n &#34;${sampname}&#34; --outdir &#34;$bdir/peaks&#34; done output 파일 구조 # /data-blog/bi5/samples/ ├── trimmed/ │ ├── Input/ │ │ ├── Input_1.trimmed.fastq │ │ ├── Input_1.unpaired.fastq │ │ ├── Input_2.trimmed.fastq │ │ ├── Input_2.unpaired.fastq │ │ └── log.txt │ ├── p65/ │ │ └── (동일 구조) │ └── RIgG/ │ └── (동일 구조) /data-blog/bi5/res/ ├── aln/ │ ├── bwa/ │ │ ├── Input_PE.bwa.sam │ │ ├── Input_PE.bwa.bam │ │ ├── Input_PE.bwa.bam.bai │ │ ├── Input_PE.bwa.bam.bigwig │ │ └── (동일 구조) │ ├── bwt2/ │ │ ├── Input_PE_hg38.sam │ │ ├── Input_PE_hg38.bam │ │ ├── Input_PE_hg38.bam.bai │ │ ├── Input_PE_hg38_u.bam │ │ └── (동일 구조) └── peaks/ ├── Input_peaks.narrowPeak └── (동일 구조) additional data # 코드에 사용된 데이터 정보는 github에서 확인 가능하다.

